+        box.setFillWidth(false);
+        box.getChildren().addAll(a, b);
+
+        scene.setRoot(box);
+        stage.show();
+        Toolkit.getToolkit().firePulse();
+
+        b.requestFocus();
+        Toolkit.getToolkit().firePulse();
+        assertTrue(b.isFocused());
+
+        Text promptNode = TextInputSkinShim.getPromptNode(a);
